## Create File 1: `src/modules/jira/jira.module.ts`

```typescript
import { HttpModule } from '@nestjs/axios';
import { BullModule } from '@nestjs/bullmq';
import { Module, OnModuleInit } from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';

import { CacheModule } from '@modules/cache/cache.module';
import { DbModule } from '@modules/db/db.module';
import { EnvConfigModule } from '@modules/env-config/env-config.module';
import { JiraChangelogModel } from '@modules/jira/db/jira-changelog.model';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';
import { JiraIssueModel } from '@modules/jira/db/jira-issues.model';
import { JiraProjectModel } from '@modules/jira/db/jira-projects.model';
import { JiraSprintModel } from '@modules/jira/db/jira-sprints.model';
import { JiraWorklogModel } from '@modules/jira/db/jira-worklogs.model';
import { JiraApiService } from '@modules/jira/jira-api.service';
import { JiraInstallService } from '@modules/jira/jira-install.service';
import { JiraProcessor } from '@modules/jira/jira-processor.service';
import { JiraSyncService } from '@modules/jira/jira-sync.service';
import { JiraController } from '@modules/jira/jira.controller';

const TWELVE_HOURS_MS = 12 * 60 * 60 * 1000;

@Module({
	imports: [
		HttpModule,
		CacheModule,
		DbModule,
		EnvConfigModule,
		BullModule.registerQueue({ name: 'jira' }),
	],
	controllers: [JiraController],
	providers: [
		JiraInstallationModel,
		JiraProjectModel,
		JiraIssueModel,
		JiraChangelogModel,
		JiraWorklogModel,
		JiraSprintModel,
		JiraApiService,
		JiraInstallService,
		JiraSyncService,
		JiraProcessor,
	],
})
export class JiraModule implements OnModuleInit {
	constructor(@InjectQueue('jira') private readonly jiraQueue: Queue) {}

	async onModuleInit(): Promise<void> {
		await this.jiraQueue.add(
			'poll_installations',
			{ triggeredAt: new Date().toISOString() },
			{
				repeat: { every: TWELVE_HOURS_MS },
				jobId: 'poll_installations_cron',
			},
		);
	}
}
```

## Modify File 2: `src/modules/app/app.module.ts`

Add `JiraModule` to the imports array. Steps:
1. Read the current `app.module.ts`
2. Add this import line (sorted with other module imports):
   `import { JiraModule } from '@modules/jira/jira.module';`
3. Add `JiraModule` to the `imports` array, after `GithubModule`

## Steps

1. Read `src/modules/github/github.module.ts` and `src/modules/app/app.module.ts`
2. Write `src/modules/jira/jira.module.ts` exactly as above
3. Edit `src/modules/app/app.module.ts` to add JiraModule
